42	// NewService 创建开发机服务
43	func NewService(k8sClient k8s.Client, cfg *config.Config) Service {
44		// 初始化CSI配置
45		if err := SyncCSIConfigFromStorageClass(k8sClient); err != nil {
46			log.Printf("warning: failed to sync CSI config from storage class: %v", err)
47		}
48	
49		// 检查并创建集群共享 PV（如不存在则自动创建）
50		svc := &service{k8sClient: k8sClient, config: cfg}
51		if err := svc.ensureSharedPVs(context.Background()); err != nil {
52			log.Printf("warning: failed to ensure shared PVs: %v", err)
53		}
54	
55		// 启动CSI配置同步循环
56		StartCSISyncLoop(k8sClient)
57	
58		// 启动Ingress URL同步循环
59		StartIngressURLSyncLoop(k8sClient)
60	
61		return svc
62	}
