314	// getStatusFromDeployment 从Deployment获取状态
315	// TODO: 添加pod级别的状态判断
316	func getStatusFromDeployment(deployment *appsv1.Deployment) string {
317		if deployment.Status.ReadyReplicas > 0 {
318			return "running"
319		}
320		if deployment.Status.Replicas == 0 {
321			return "stopped"
322		}
323		return "pending"
324	}
