467	// ensureSharedPVCs 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 无 PVC 时补建）
468	// TODO: 新环境稳定后可移除
469	func (s *service) ensureSharedPVCs(ctx context.Context, namespace string, storages []devmachinemodel.Storage) error {
470		needsRW, needsRO := false, false
471		for _, st := range storages {
472			if st.ReadOnly {
473				needsRO = true
474			} else {
475				needsRW = true
476			}
477		}
478	
479		if needsRW {
480			if err := s.ensurePVCExists(ctx, namespace, SharedRWPVCName, s.config.SharedStorage.RWPV.Name, false); err != nil {
481				return err
482			}
483		}
484		if needsRO {
485			if err := s.ensurePVCExists(ctx, namespace, SharedROPVCName, s.config.SharedStorage.ROPV.Name, true); err != nil {
486				return err
487			}
488		}
489		return nil
490	}
