518	func (s *service) CreateNamespace(ctx context.Context, request *devmachinemodel.CreateNamespaceRequest) (*devmachinemodel.CreateNamespaceResponse, error) {
519		// 验证请求参数
520		if request.Namespace == "" {
521			return nil, NewValidationError("namespace", request.Namespace, fmt.Errorf("namespace cannot be empty"))
522		}
523	
524		// 创建命名空间
525		if err := s.k8sClient.CreateNamespace(ctx, request.Namespace); err != nil {
526			return nil, NewResourceError("Namespace", request.Namespace, "create", err)
527		}
528	
529		// 为新 namespace 创建共享 PVC
